const headers = $input.item.json.headers || {};
const body    = $input.item.json.body    || {};
const auth    = headers['authorization'] || headers['Authorization'] || '';
const token   = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { ok: false, status: 401, error: 'Missing session token' } };

const f = body.filters || {};
const avatarName = (f.avatar_name || 'AVA').trim();
const limit = Math.min(Math.max(parseInt(f.limit, 10) || 200, 1), 1000);

// Avatar lookup query (resolves name -> id)
const qsAvatar = 'select=id,avatar_name,personality,vertical_id,broadcast_window,active&avatar_name=eq.' + encodeURIComponent(avatarName) + '&limit=1';

// Content topics — embed via avatars FK so we get name back in same call
const qsTopics = [
  'select=id,vertical,avatar_id,topic_title,topic_description,generated_by,status,priority_score,created_at',
  'order=priority_score.desc,created_at.desc',
  'limit=' + limit
].join('&');

return { json: { token: token, qs_avatar: qsAvatar, qs_topics_base: qsTopics, avatar_name: avatarName, status_filter: f.status || null } };

const rows = $input.item.json;
const row  = Array.isArray(rows) ? (rows[0] || null) : (rows && (rows.user_id || rows.id) ? rows : null);
if (!row) return { json: { ok: false, status: 401, error: 'Invalid or expired session' } };
if (row.user_role !== 'admin') return { json: { ok: false, status: 403, error: 'Admin access required' } };
const x = $('Extract Inputs').item.json;
return { json: { ok: true, qs_avatar: x.qs_avatar, qs_topics_base: x.qs_topics_base, avatar_name: x.avatar_name, status_filter: x.status_filter } };

// Resolve avatar row → use its id to build the topics query.
const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    if (items.length === 1 && items[0] && typeof items[0] === 'object' && !Array.isArray(items[0]) && items[0].id) return [items[0]];
    return items.filter(function (x) { return x && x.id; });
  } catch (e) { return []; }
};
const avatars = allOf('Lookup Avatar');
const x       = $('Check Admin').item.json;
if (avatars.length === 0) {
  return { json: { _no_avatar: true, error: 'Avatar not found: ' + x.avatar_name, status: 404 } };
}
const avatar = avatars[0];
let qs = 'avatar_id=eq.' + avatar.id + '&' + x.qs_topics_base;
if (x.status_filter) qs += '&status=eq.' + encodeURIComponent(x.status_filter);
return { json: { qs_topics: qs, avatar: avatar } };

// Classify each topic into one of 5 streams based on the
// vanity-UUID pattern `00000000-a0a0-NNNN-MMMM-...`. Look at the
// 3rd UUID group (NNNN, hex) and bucket:
//
//   <= 0x0016  → insurance_education  (Stream 1)
//   <= 0x0028  → advisor_recruitment  (Stream 2)
//   <= 0x0036  → carrier_partnership  (Stream 3)
//   <= 0x0047  → advisorassist_promo  (Stream 4)
//   <= 0x0056  → ribo_study_coach     (Stream 5)
//   else       → other                (catch-all)
//
// Topics inserted by future workflows that don't use the vanity
// prefix fall into 'other' — fine, they'll surface in their own
// section so Mary can still see them.
const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    if (items.length === 1 && items[0] && typeof items[0] === 'object' && !Array.isArray(items[0]) && items[0].id) return [items[0]];
    return items.filter(function (x) { return x && x.id; });
  } catch (e) { return []; }
};

const topics = allOf('Query Topics');
const avatar = $('Build Topics Query').first().json.avatar;

function streamOf(id) {
  const m = (id || '').match(/^[0-9a-f]{8}-[0-9a-f]{4}-([0-9a-f]{4})/i);
  if (!m) return 'other';
  const code = parseInt(m[1], 16);
  if (code <= 0x0016) return 'insurance_education';
  if (code <= 0x0028) return 'advisor_recruitment';
  if (code <= 0x0036) return 'carrier_partnership';
  if (code <= 0x0047) return 'advisorassist_promo';
  if (code <= 0x0056) return 'ribo_study_coach';
  return 'other';
}

const byStream = {
  insurance_education: [],
  advisor_recruitment: [],
  carrier_partnership: [],
  advisorassist_promo: [],
  ribo_study_coach:    [],
  other:               []
};
const byStatus = {};

topics.forEach(function (t) {
  const s = streamOf(t.id);
  byStream[s].push(t);
  byStatus[t.status || 'unknown'] = (byStatus[t.status || 'unknown'] || 0) + 1;
});

// Sort each stream's topics by priority_score desc.
Object.keys(byStream).forEach(function (k) {
  byStream[k].sort(function (a, b) { return (b.priority_score || 0) - (a.priority_score || 0); });
});

return { json: {
  ok: true,
  avatar: avatar,
  topics: topics,
  by_stream: byStream,
  by_status: byStatus,
  counts: {
    total: topics.length,
    insurance_education: byStream.insurance_education.length,
    advisor_recruitment: byStream.advisor_recruitment.length,
    carrier_partnership: byStream.carrier_partnership.length,
    advisorassist_promo: byStream.advisorassist_promo.length,
    ribo_study_coach:    byStream.ribo_study_coach.length,
    other:               byStream.other.length
  }
} };
